import React, { useEffect, useState } from "react";
import axios from "axios";

function Cart(){

const [cart,setCart] = useState(null);

const userId = 1;

useEffect(()=>{

axios.get(`http://localhost:8080/api/cart/${userId}`)
.then(res=>{
setCart(res.data);
})
.catch(err=>{
console.log(err);
});

},[]);

const increaseQuantity = (productId) => {

axios.put(`http://localhost:8080/api/cart/increase?userId=${userId}&productId=${productId}`)
.then(()=>{
window.location.reload();
});

};

const decreaseQuantity = (productId) => {

axios.put(`http://localhost:8080/api/cart/decrease?userId=${userId}&productId=${productId}`)
.then(()=>{
window.location.reload();
});

};

const placeOrder = () => {

axios.post(`http://localhost:8080/api/orders/place?userId=1`)
.then(res=>{
console.log(res.data);
alert("Order Placed Successfully ✅");
window.location.reload();
})
.catch(err=>{
console.log(err);
});

};

if(!cart){
return <h2>Loading Cart...</h2>
}

let total = 0;

return(

<div>

<h2>My Cart</h2>

{cart.items.map(item =>{

total += item.product.price * item.quantity;

return(

<div key={item.id} style={{border:"1px solid gray",padding:"10px",margin:"10px"}}>

<h3>{item.product.name}</h3>

<p>Price: {item.product.price}</p>

<div>

<button onClick={()=>decreaseQuantity(item.product.id)}>-</button>

<span style={{margin:"10px"}}>{item.quantity}</span>

<button onClick={()=>increaseQuantity(item.product.id)}>+</button>

</div>

</div>

);

})}

<h3>Total Price: {total}</h3>

<button onClick={placeOrder}>Place Order</button>

</div>

);

}

export default Cart;
